#include <stdio.h>
#include <stdlib.h>

int maxFrequency(int* arr, int size) {
    int maxFreq = 0;
    int* freq = (int*)calloc(1000001, sizeof(int));
    for (int i = 0; i < size; i++) {
        freq[arr[i]]++;
        if (freq[arr[i]] > maxFreq) {
            maxFreq = freq[arr[i]];
        }
    }
    free(freq);
    return maxFreq;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int** A = (int**)malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            A[i] = (int*)malloc(M * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &A[i][j]);
            }
        }
        int maxElement = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                int* row = (int*)malloc(N * sizeof(int));
                int* col = (int*)malloc(M * sizeof(int));
                int rowSize = 0;
                int colSize = 0;
                for (int k = 0; k < N; k++) {
                    row[rowSize++] = A[k][j];
                }
                for (int k = 0; k < M; k++) {
                    col[colSize++] = A[i][k];
                }
                int* Sij = (int*)malloc((N + M - 1) * sizeof(int));
                int SijSize = 0;
                for (int k = 0; k < rowSize; k++) {
                    if (row[k] != A[i][j]) {
                        Sij[SijSize++] = row[k];
                    }
                }
                for (int k = 0; k < colSize; k++) {
                    if (col[k] != A[i][j]) {
                        Sij[SijSize++] = col[k];
                    }
                }
                int freq = maxFrequency(Sij, SijSize);
                if (freq > maxElement) {
                    maxElement = freq;
                }
                free(row);
                free(col);
                free(Sij);
            }
        }
        printf("%d\n", maxElement);
        for (int i = 0; i < N; i++) {
            free(A[i]);
        }
        free(A);
    }
    return 0;
}

