#include <iostream>
#include <vector>
#include <unordered_map>
using namespace std;

int maxFrequency(vector<int>& arr) {
    unordered_map<int, int> freq;
    int maxFreq = 0;
    for (int num : arr) {
        freq[num]++;
        if (freq[num] > maxFreq) {
            maxFreq = freq[num];
        }
    }
    return maxFreq;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int N, M;
        cin >> N >> M;
        vector<vector<int>> A(N, vector<int>(M));
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                cin >> A[i][j];
            }
        }
        int maxElement = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                vector<int> row;
                vector<int> col;
                for (int k = 0; k < N; k++) {
                    row.push_back(A[k][j]);
                }
                for (int k = 0; k < M; k++) {
                    col.push_back(A[i][k]);
                }
                vector<int> Sij;
                for (int k = 0; k < row.size(); k++) {
                    if (row[k] != A[i][j]) {
                        Sij.push_back(row[k]);
                    }
                }
                for (int k = 0; k < col.size(); k++) {
                    if (col[k] != A[i][j]) {
                        Sij.push_back(col[k]);
                    }
                }
                int freq = maxFrequency(Sij);
                if (freq > maxElement) {
                    maxElement = freq;
                }
            }
        }
        cout << maxElement << endl;
